import{_ as a,o as r,c as t,ag as i}from"./chunks/framework.-Wrcbzkw.js";const d=JSON.parse('{"title":"UI / UX &amp; Design 资源官网合集","description":"","frontmatter":{},"headers":[],"relativePath":"LLM/资源/前端设计skill网站.md","filePath":"LLM/资源/前端设计skill网站.md","lastUpdated":1778766566000}'),p={name:"LLM/资源/前端设计skill网站.md"};function s(o,e,l,n,h,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="ui-ux-amp-design-资源官网合集" tabindex="-1">UI / UX &amp; Design 资源官网合集 <a class="header-anchor" href="#ui-ux-amp-design-资源官网合集" aria-label="Permalink to &quot;UI / UX &amp;amp; Design 资源官网合集&quot;">​</a></h1><h2 id="_1-anthropic-ui-产品体验相关公司" tabindex="-1">1. Anthropic（UI/产品体验相关公司） <a class="header-anchor" href="#_1-anthropic-ui-产品体验相关公司" aria-label="Permalink to &quot;1. Anthropic（UI/产品体验相关公司）&quot;">​</a></h2><p><a href="https://www.anthropic.com" target="_blank" rel="noreferrer">https://www.anthropic.com</a></p><p>Claude 的官方公司</p><p>他们本身不专注 UI 框架，但产品交互设计很有参考价值</p><p>重点看 Claude UI / AI 交互范式</p><hr><h2 id="_2-ui-ux-pro-max-ai-ui设计技能库" tabindex="-1">2. UI UX Pro Max（AI UI设计技能库） <a class="header-anchor" href="#_2-ui-ux-pro-max-ai-ui设计技能库" aria-label="Permalink to &quot;2. UI UX Pro Max（AI UI设计技能库）&quot;">​</a></h2><p><a href="https://ui-ux-pro-max-skill.com" target="_blank" rel="noreferrer">https://ui-ux-pro-max-skill.com</a></p><p>AI UI设计&quot;设计系统数据库&quot;</p><p>包含：配色 / 字体 / 风格 / UX规则</p><p>很多 Cursor / Claude Code 用户在用</p><hr><h2 id="_3-impeccable-ui-ui-skill" tabindex="-1">3. Impeccable UI（UI skill） <a class="header-anchor" href="#_3-impeccable-ui-ui-skill" aria-label="Permalink to &quot;3. Impeccable UI（UI skill）&quot;">​</a></h2><p><a href="https://impeccable-ui.com" target="_blank" rel="noreferrer">https://impeccable-ui.com</a></p><p>偏&quot;AI UI设计规范库&quot;</p><p>用于生成更干净的界面风格</p><p>和 UI UX Pro Max 属于同一类工具生态</p><hr><h2 id="_4-uiux-pro-max-官方文档-介绍" tabindex="-1">4. UIUX Pro Max（官方文档/介绍） <a class="header-anchor" href="#_4-uiux-pro-max-官方文档-介绍" aria-label="Permalink to &quot;4. UIUX Pro Max（官方文档/介绍）&quot;">​</a></h2><p><a href="https://uupm.cc" target="_blank" rel="noreferrer">https://uupm.cc</a></p><p><a href="https://ui-ux-pro-max-skill.com" target="_blank" rel="noreferrer">https://ui-ux-pro-max-skill.com</a></p><p>设计系统增强 AI 输出质量</p><p>强调：style + UX + typography + spacing</p><hr><h2 id="_5-0xdesign-设计灵感-前端设计社区" tabindex="-1">5. 0xDesign（设计灵感/前端设计社区） <a class="header-anchor" href="#_5-0xdesign-设计灵感-前端设计社区" aria-label="Permalink to &quot;5. 0xDesign（设计灵感/前端设计社区）&quot;">​</a></h2><p><a href="https://0xdesign.dev" target="_blank" rel="noreferrer">https://0xdesign.dev</a></p><p>偏前端 + UI + 产品设计审美</p><p>很多 AI UI / Dev UI 风格参考来源</p><p>极简 + 工程师审美</p><hr><h2 id="_6-user-interface-wiki-ui模式百科" tabindex="-1">6. User Interface Wiki（UI模式百科） <a class="header-anchor" href="#_6-user-interface-wiki-ui模式百科" aria-label="Permalink to &quot;6. User Interface Wiki（UI模式百科）&quot;">​</a></h2><p><a href="https://ui-patterns.com" target="_blank" rel="noreferrer">https://ui-patterns.com</a></p><p>UI设计模式百科全书</p><p>比如：modal / sidebar / dashboard pattern</p><p>非常适合系统学习 UI 结构</p><hr><h2 id="_7-designer-skills-设计能力学习体系" tabindex="-1">7. Designer Skills（设计能力学习体系） <a class="header-anchor" href="#_7-designer-skills-设计能力学习体系" aria-label="Permalink to &quot;7. Designer Skills（设计能力学习体系）&quot;">​</a></h2><p><a href="https://www.nngroup.com" target="_blank" rel="noreferrer">https://www.nngroup.com</a></p><p>（Nielsen Norman Group，权威 UX 机构）</p><p>UX行业标准来源</p><p>可用性测试 / 信息架构 / 交互设计核心理论</p><hr><h2 id="_8-make-interfaces-better-ui改进理念" tabindex="-1">8. Make Interfaces Better（UI改进理念） <a class="header-anchor" href="#_8-make-interfaces-better-ui改进理念" aria-label="Permalink to &quot;8. Make Interfaces Better（UI改进理念）&quot;">​</a></h2><p><a href="https://lawsofux.com" target="_blank" rel="noreferrer">https://lawsofux.com</a></p><p>UX 设计 10 大法则</p><p>比如：Hick&#39;s Law / Fitts&#39;s Law</p><p>非常适合提升&quot;设计判断力&quot;</p><hr><h2 id="_9-uiux-wiki-design-wiki-通用-ui知识库" tabindex="-1">9. UIUX Wiki / Design Wiki（通用 UI知识库） <a class="header-anchor" href="#_9-uiux-wiki-design-wiki-通用-ui知识库" aria-label="Permalink to &quot;9. UIUX Wiki / Design Wiki（通用 UI知识库）&quot;">​</a></h2><p><a href="https://www.uxdesign.cc" target="_blank" rel="noreferrer">https://www.uxdesign.cc</a></p><p>Medium 上最活跃的 UX 设计社区</p><p>UI趋势 / 案例 / 产品拆解</p><hr><h2 id="_10-uiux-pro-design-systems-广义设计系统参考" tabindex="-1">10. UIUX Pro / Design Systems（广义设计系统参考） <a class="header-anchor" href="#_10-uiux-pro-design-systems-广义设计系统参考" aria-label="Permalink to &quot;10. UIUX Pro / Design Systems（广义设计系统参考）&quot;">​</a></h2><p><a href="https://material.io" target="_blank" rel="noreferrer">https://material.io</a></p><p>Google Material Design 官方</p><p>UI设计标准体系（颜色 / spacing / motion）</p>',58)])])}const m=a(p,[["render",s]]);export{d as __pageData,m as default};
